/**
 * Execute chat with a single agent
 */
async function* executeSingleAgent(
  agentId: string,
  request: ChatRequest,
  command: AgentCommand | null,
  abortController: AbortController,
  debugMode: boolean,
  activeAgentIds: string[] = [],
  reportProviderErrors: boolean = true
): AsyncGenerator<StreamResponse> {
  const result = yield* runAgent(
    agentId,
    request,
    command,
    abortController,
    debugMode,
    activeAgentIds,
    reportProviderErrors
  );

  if (result.isError && reportProviderErrors) {
    yield { type: "error", error: result.content };
  }
}

interface AgentRunResult {
  content: string;
  isError: boolean;
}

interface DelegateTaskInput {
  agent_id?: unknown;
  instructions?: unknown;
}

const NO_TEXT_RESULT = "The delegated agent completed without producing text.";

function toolResultContent(toolUseId: string, result: AgentRunResult): string {
  return JSON.stringify({
    type: "tool_result",
    is_error: result.isError,
    content: result.content || NO_TEXT_RESULT,
    tool_use_id: toolUseId,
  });
}

function delegationInput(input: unknown): { agentId: string; instructions: string } | null {
  if (!input || typeof input !== "object") return null;

  const { agent_id, instructions } = input as DelegateTaskInput;
  if (typeof agent_id !== "string" || typeof instructions !== "string") return null;

  return { agentId: agent_id, instructions };
}

function streamToolUse(toolUseId: string, toolName: string, toolInput: unknown): StreamResponse {
  return {
    type: "claude_json",
    data: {
      type: "assistant",
      message: {
        content: [{ type: "tool_use", id: toolUseId, name: toolName, input: toolInput ?? {} }],
      },
    },
  };
}

function streamToolResult(toolUseId: string, content: string, isError: boolean): StreamResponse {
  return {
    type: "claude_json",
    data: {
      type: "user",
      message: {
        content: [{ type: "tool_result", tool_use_id: toolUseId, content, is_error: isError }],
      },
    },
  };
}

